	public static function refundEcomOrder($dataArray){
		$globalEcomOrderSummaryTable = Constants::getGlobalTableName("globalEcomOrderSummary");
		$globalEcomOrderPaymentsTable = Constants::getGlobalTableName("globalEcomOrderPayments");
		$listOfStoresTable = Constants::getGlobalTableName("listOfStores");

		$refundPayArray = array();

		if (!isset($dataArray["storeID"]) || empty($dataArray["storeID"]) || $dataArray["storeID"] <= 0) {
			$status["status"] = false;
			$status["message"] = "Store ID not provided";

			return $status;
		}

		if (!isset($dataArray["chainID"]) || empty($dataArray["chainID"]) || $dataArray["chainID"] <= 0) {
			$status["status"] = false;
			$status["message"] = "Chain ID not provided";

			return $status;
		}

		if (!isset($dataArray["proformaInvoiceID"]) || empty($dataArray["proformaInvoiceID"])) {
			$status["status"] = false;
			$status["message"] = "Proforma Invoice ID not provided";

			return $status;
		}
		$storeID = $dataArray["storeID"];
		$chainID = $dataArray["chainID"];
		$defaultSMS = Constants::getChainDefaultSMS($chainID);
		$proformaInvoiceID = $dataArray["proformaInvoiceID"];

		$PIPaymentsTable = Constants::getChainTableName($chainID,"PIPayments");
		$PISummaryTable      = Constants::getChainTableName($chainID, "PISummary");

		$checkOrder = convertToArray(DB::table($globalEcomOrderSummaryTable)->where("proformaInvoiceID",$proformaInvoiceID)->where("storeID",$storeID)->where("chainID",$chainID)->select("externalOrderID","customersIDs")->get());
		if (empty($checkOrder)) {
			$status["status"] = false;
			$status["message"] = "Invalid order ID";

			return $status;
		}

		$payList = convertToArray(DB::table($globalEcomOrderPaymentsTable)->where("proformaInvoiceID",$proformaInvoiceID)->where("storeID",$storeID)->where("chainID",$chainID)->get());

		$refundAmount = 0;

		$count = count($payList);
		$paymentTransactionID = "";

		for ($i=0; $i < $count; $i++) { 
			$tempPayArray = $payList[$i];
			if ($tempPayArray["paymentType"] != 'PAYMENT_VOUCHER' || $tempPayArray["paymentType"] != 'PAYMENT_PARTY' || $tempPayArray["paymentType"] != "PAYMENT_LOYALTY" || $tempPayArray["paymentType"] != "PAYMENT_CASH") {
				$refundAmount += $tempPayArray["amount"];
				$paymentTransactionID = $tempPayArray["transactionID"];
			}

			$tempPayArray["transactionType"] = "TRN_ORDER_CANCEL";
			$tempPayArray["amount"]= (-1)*$tempPayArray["amount"];
			array_push($refundPayArray, $tempPayArray);

		}

        $checkLastRefund = convertToArray(DB::table($globalEcomOrderSummaryTable)
                     ->where('chainID',$chainID)
                     ->where('storeID',$storeID)
                     ->whereIn('deliveryStatus',['Rejected','Expired','REJECTED','EXPIRED'])
                     ->orderBy('ID', 'DESC')
                     ->get());

        if(empty($checkLastRefund)){

        	$refPINumber = "PI-REF-".$chainID."-".$storeID."-1";
        } else{

        	$existingrefPINumber = $checkLastRefund[0]['proformaInvoiceID'];

        	$PIArray = explode('-', $existingrefPINumber);
        	if (empty($PIArray)) {
        		$status["status"] = false;
        		$status["message"] = "Invalid sequence of proformaInvoiceID";

        		return $status;
        	}
        	$lastNumber = end($PIArray);

        	$nextNumber = $lastNumber+1;

        	$refPINumber = "PI-REF-".$chainID."-".$storeID."-".$nextNumber;
        }

        $refSumArray = array();
        $refSumArray["refundOrderID"] = $refPINumber;
        $refSumArray["proformaInvoiceID"] = $proformaInvoiceID;

		if ($refundAmount > 0 && $paymentTransactionID!= "") {
			$refundArr = array();
			$refundArr["storeID"] = $storeID;
			$refundArr["chainID"] = $chainID;
			$refundArr["proformaInvoiceID"] = $proformaInvoiceID;
			$refundArr["amount"] = $refundAmount;
			$refundArr["gatewayPaymentID"] = $paymentTransactionID;
			$refundArr["refundOrderID"] = $refPINumber;
			$ecomOrderRefund = self::refundEcomPayment($refundArr);
			if ($ecomOrderRefund["status"] == false) {
				return $ecomOrderRefund;
			}
		}


		DB::transaction(function()use($refundPayArray,$PIPaymentsTable,$globalEcomOrderPaymentsTable,$globalEcomOrderSummaryTable,$refSumArray,$defaultSMS,$proformaInvoiceID){
			$count = count($refundPayArray);
			for ($i=0; $i < $count; $i++) { 
				if (isset($refundPayArray[$i]["ID"])) {
					unset($refundPayArray[$i]["ID"]);
				}

				DB::table($globalEcomOrderPaymentsTable)->insert($refundPayArray[$i]);
				date_default_timezone_set("Asia/Kolkata");
				$PITimeLocal = date("Y-m-d H:i:s");

				date_default_timezone_set("UTC");
				$PITimeUTC = date("Y-m-d H:i:s");

				if (isset($refundPayArray[$i]["chainID"])) {
					unset($refundPayArray[$i]["chainID"]);
				}

				if (isset($refundPayArray[$i]["globalEcomCustomerID"])) {
					unset($refundPayArray[$i]["globalEcomCustomerID"]);
				}

				$refundPayArray[$i]["PITimeLocal"] = $PITimeLocal;
				$refundPayArray[$i]["PITimeUTC"] = $PITimeUTC;

				DB::table($PIPaymentsTable)->insert($refundPayArray[$i]);
			}

			unset($refSumArray["proformaInvoiceID"]);
			DB::table($globalEcomOrderSummaryTable)->where("proformaInvoiceID",$proformaInvoiceID)->update($refSumArray);
		});

		// Send notification to customer					
		$globalCustomer = self::getGlobalCustomerDetails($chainID, $proformaInvoiceID);
		$status["globalCustomer"] = $globalCustomer;
		if (isset($globalCustomer) && !empty($globalCustomer) && $chainID != 60631) {
			$storeDetails = convertToArray(DB::table($listOfStoresTable)->where("storeID",$storeID)->select("storeName")->get());

			// Get PI Details
			$PIdetails = convertToArray(DB::select(DB::raw("SELECT A.currencyCode, A.grossBill FROM $PISummaryTable AS A  WHERE A.proformaInvoiceID = ?"),[$proformaInvoiceID]));

			$orderDetails = array();
			$orderDetails["orderID"] = $proformaInvoiceID;
			$orderDetails["storeID"] = $storeID;
			$orderDetails["storeName"] = $storeDetails[0]["storeName"];
			if(strtoupper($defaultSMS)=='SPARROW'){
				$orderDetails["orderAmount"] = "NPR ".number_format((float)$PIdetails[0]["grossBill"], 2, '.', '');
			} else{
				$orderDetails["orderAmount"] = $PIdetails[0]["currencyCode"]." ".number_format((float)$PIdetails[0]["grossBill"], 2, '.', '');
			}
			$orderDetails["defaultSMS"] = $defaultSMS;
			$orderDetails["chainID"] = $chainID;

			$notifArray = self::generateNotifArray($globalCustomer, "ORDER_UPDATE", "EXPIRED", $orderDetails);

			$queueNumber = "customer";
			if ($globalCustomer["isContactAllowed"] == 1) {
				$fcmNotificationjob = (new EcomFCMJob($notifArray))->onQueue("$queueNumber");
				$whatsappNotificationjob = (new EcomWhatsappJob($notifArray))->onQueue("$queueNumber");
				dispatch($fcmNotificationjob);
				dispatch($whatsappNotificationjob);
				$status["fcmNotificationjob"] = $fcmNotificationjob;
				$status["whatsappNotificationjob"] = $whatsappNotificationjob;
			}
			$notifArray['defaultSMS'] = $defaultSMS;
			$SMSNotificationjob = (new EcomSMSJob($notifArray))->onQueue("$queueNumber");
			dispatch($SMSNotificationjob);
			//$SMSNotificationjob = self::sendSMS($SMSNotificationjob);
			$responseStatus["SMSNotificationjob"] = $SMSNotificationjob;
			$status["notifArray"] = $notifArray;
		}

		$status["status"] = true;
		$status["message"] = "Order successfully refunded";

		return $status;


	}
