    public function updateOrderStatus(Request $request){
        $result = $request->getContent();
        if (isJson($result) == FALSE) {
            $client = "Invalid Data";
            return response()->json($client,422,[],JSON_NUMERIC_CHECK);
        }

        $chainID = $request->segment(3);
        $data = convertToArray(json_decode($result));

        $v = new V($data);
        $v->rule("required", array("aggregatorId","posAppId","transactionType","orderID","storeID"));
        if (!$v->validate()) {
            $status["status"] = false;
            $status["message"] = $v->errors();
            return response()->json($status, 422, [], JSON_NUMERIC_CHECK);
        }

        $response = WorldLine::updateOrderStatus($data, $chainID);
        return $response;
        return response()->json($response,201,[],JSON_NUMERIC_CHECK);
    }


