public function validateCoupon(Request $request)
{
	$result = $request->getContent();

	if (isJson($result) == false) {
		$client = "Invalid Data";
		return response()->json($client, 422, [], JSON_NUMERIC_CHECK);
	}

	$chainID = $request->segment(3);
	$data = convertToArray(json_decode($result));
	$coupon = Product::validateCoupon($data, $chainID);
	if ($coupon["status"] == 1) {
		return response()->json($coupon, 201, []);
	} else {
		return response()->json($coupon, 422, []);
	}
}

