  if (isJson($result) == FALSE) {
      $client = "Invalid Data";
      return response()->json($client,422,[],JSON_NUMERIC_CHECK);
  }
  $chainID = $request->segment(3);
  $data = convertToArray(json_decode($result));
  $response = Paytm::cancelPayment($data, $chainID);
  return response()->json($response,200,[]);
}

// refund paytm payment
public function refundPaytmPayment(Request $request){
  $result = $request->getContent();
  if (isJson($result) == FALSE) {
      $client = "Invalid Data";
      return response()->json($client,422,[],JSON_NUMERIC_CHECK);
  }
  $chainID = $request->segment(3);
  $data = convertToArray(json_decode($result));
  $response = Paytm::refundPayment($data, $chainID);
