	/**
	 * Paytm Cloud Payment - Check Refund Status
	 * Checks the status of a refund transaction using Paytm Cloud Payment API
	 * 
	 * @param array $dataArray Refund status check data including:
	 *   - orderId: Order ID (mandatory)
	 *   - refId: Refund reference ID (mandatory)
	 *   - deviceID: Device ID (optional, used to fetch credentials)
	 *   - storeID: Store ID (optional, for logging)
	 * @param int $chainID Chain ID
	 * @return array Status array with success/failure and response data
	 */
	public static function checkRefundStatus($dataArray, $chainID)
	{
		$listOfChainsTable = Constants::getGlobalTableName('listOfChains');
		$thirdPartyPaymentIntentTable = Constants::getChainTableName($chainID, 'thirdPartyPaymentIntent');
		$devicePaymentConfiguration = Constants::getGlobalTableName('devicePaymentConfiguration');

		// Fetch chain details
		$fetchChainDetail = convertToArray(DB::table($listOfChainsTable)->where('chainID', $chainID)->get());
		if(empty($fetchChainDetail)){
			$status["status"] = false;
			$status["message"] = "Invalid chain ID";
			return $status;
		}

		// Validate mandatory fields
		if(empty($dataArray['orderID']) || empty($dataArray['refID'])){
			$status["status"] = false;
			$status["message"] = "orderID and refID are required";
			return $status;
		}

		// Get orderId and refId
		$orderID = $dataArray['orderID'];
		$refID = $dataArray['refID'];

		// Fetch deviceID and storeID from payment intent if not provided
		$deviceID = '';
		$storeID = '';

		if(isset($dataArray['deviceID']) && !empty($dataArray['deviceID'])){
			$deviceID = $dataArray['deviceID'];
		}

		if(isset($dataArray['storeID']) && !empty($dataArray['storeID'])){
			$storeID = $dataArray['storeID'];
		}

		// If deviceID or storeID not provided, fetch from payment intent
		if(empty($deviceID) || empty($storeID)){
			$fetchPaymentIntent = convertToArray(DB::table($thirdPartyPaymentIntentTable)
				->select('deviceID', 'storeID')
				->where('orderID', $orderID)
				->orderBy('ID', 'desc')
				->first());

			if(!empty($fetchPaymentIntent)){
				if(empty($deviceID)){
					$deviceID = isset($fetchPaymentIntent[0]['deviceID']) ? $fetchPaymentIntent[0]['deviceID'] : '';
				}
				if(empty($storeID)){
					$storeID = isset($fetchPaymentIntent[0]['storeID']) ? $fetchPaymentIntent[0]['storeID'] : '';
				}
			}
		}

		// Fetch credentials from device payment configuration
		$paytmMid = '';
		$paytmMerchantKey = '';

		$fetchDevicePaymentConfiguration = convertToArray(DB::table($devicePaymentConfiguration)
			->where('deviceID', $deviceID)
			->where('storeID', $storeID)
			->where('chainID', $chainID)
			->where('paymentMode', 'PAYMENT_CARD')
			->where('isActive', 1)
			->get());

		if(!empty($fetchDevicePaymentConfiguration)){
			$paytmMid = $fetchDevicePaymentConfiguration[0]['aggregatorID'];
			$paytmMerchantKey = $fetchDevicePaymentConfiguration[0]['aggregatorID3'];
		} else {
			$status['status'] = false;
			$status['message'] = "Device payment configuration not found";
			return $status;
		}

		if(empty($paytmMid) || empty($paytmMerchantKey)){
			$status['status'] = false;
			$status['message'] = "Paytm credentials (MID, Merchant Key) are required";
			return $status;
		}

		// Get API URL
		$apiUrl = env('PAYTM_CLOUD_PAYMENT_URL').'/v2/refund/status';

		// Build body array for refund status check (matching reference code)
		$paytmParams = array();
		$paytmParams["body"] = array(
			"mid"     => (string)$paytmMid,
			"orderId" => (string)$orderID,
			"refId"   => (string)$refID,
		);

		// Generate checksum (signature) from body JSON string
		$checksum = PaytmCloudChecksum::generateSignature(json_encode($paytmParams["body"], JSON_UNESCAPED_SLASHES), $paytmMerchantKey);

		// Debug logs
		Log::info("Paytm:checkRefundStatus bodyJson for checksum: ".json_encode($paytmParams["body"]));
		Log::info("Paytm:checkRefundStatus generated signature length=".strlen($checksum));
		Log::info("Paytm:checkRefundStatus orderId: ".$orderID.", refId: ".$refID);

		// Prepare request head (only signature as per reference code)
		$paytmParams["head"] = array(
			"signature" => $checksum
		);

		// Prepare final request payload
		$payload_string = json_encode($paytmParams, JSON_UNESCAPED_SLASHES);
		$headers = array('Content-Type: application/json');

		// Log request payload
		Log::info("Paytm:checkRefundStatus request payload: ".$payload_string);

		// Make API call
		$response = self::processCurlRequestCall($payload_string, $chainID, $apiUrl, $headers, 'POST', 'paytm', 'paytmCheckRefundStatus', isset($storeID) ? $storeID : (isset($dataArray['storeID']) ? $dataArray['storeID'] : 0), false);

		// Log response payload
		Log::info("Paytm:checkRefundStatus response payload: ".json_encode($response));

		// Update payment intent table with refund status check logs
		$updateArray = array();
		$updateArray['refundStatusRequestJson'] = $payload_string; // Save refund status request
		$updateArray['refundStatusResponeJson'] = json_encode($response); // Save refund status response
		$updateArray['lastUpdatedAtLocal'] = date('Y-m-d H:i:s');
		$updateArray['lastUpdatedAtUTC'] = date('Y-m-d H:i:s');

		// Update payment intent record
		if(!empty($orderID)){
			DB::table($thirdPartyPaymentIntentTable)
				->where('orderID', $orderID)
				->orderBy('ID', 'desc')
				->limit(1)
				->update($updateArray);
		}

		// Process response
		if(isset($response['body']['resultInfo'])){
			$resultInfo = $response['body']['resultInfo'];
			$resultStatus = isset($resultInfo['resultStatus']) ? $resultInfo['resultStatus'] : '';
			$resultCode = isset($resultInfo['resultCode']) ? $resultInfo['resultCode'] : '';
			$resultMsg = isset($resultInfo['resultMsg']) ? $resultInfo['resultMsg'] : '';

			if($resultStatus == 'TXN_SUCCESS' && $resultCode == '10'){
				$status['status'] = true;
				$status['message'] = "Refund status retrieved successfully";
				$status['refundStatus'] = "SUCCESS";
				$status['orderId'] = $orderID;
				$status['refId'] = $refID;
				$status['response'] = $response;
				return $status;
		return $status;	

	}

