	private static function processCurlRequestCall($payload, $chainID, $apiUrl, $headerInfo, $ReqType, $type=null,$apiName, $storeID = 0, $recordLog = true){
		if($ReqType == 'GET'){
			$apiUrl = $apiUrl."?".$payload;
			$payload = '';
		}
		$ch = curl_init($apiUrl);
		curl_setopt($ch, CURLOPT_CUSTOMREQUEST, $ReqType);
		curl_setopt($ch, CURLOPT_POSTFIELDS, $payload);
		curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
		curl_setopt($ch, CURLOPT_SSL_VERIFYHOST, 0);
		curl_setopt($ch, CURLOPT_SSL_VERIFYPEER, 0);
		curl_setopt($ch, CURLOPT_HTTPHEADER, $headerInfo);
		$jsonResponse = curl_exec($ch);
		curl_close($ch);
		$response = convertToArray(json_decode($jsonResponse, true));
		if($recordLog == true){
			$dataArray = [];
			$payloadArray = convertToArray(json_decode($payload));
			if(empty($response) && $response['success'] == true){
				$dataArray['transactionID'] = $response['p2pRequestId'];
			}else{
				$dataArray['transactionID'] = 0 ;
			}
			// Save logs
			if(isset($payloadArray['mode']) && $payloadArray['mode'] != ''){
				$paymentMode  = $payloadArray['mode'];
			}elseif($apiName == 'razorPayPaymentStatus'){
				$paymentMode = 'CHECK_STATUS';

			}elseif($apiName == 'razorVoidPayPayment'){
				$paymentMode = 'VOID_PAYMENT';

			}elseif($apiName == 'razorPayCancelPayment'){
				$paymentMode = 'CANCEL_PAYMENT';

			}
			if(isset($payloadArray['externalRefNumber']) && $payloadArray['externalRefNumber'] != ''){
				$orderID =  $payloadArray['externalRefNumber'];
			}elseif(isset($payloadArray['origP2pRequestId']) && $payloadArray['origP2pRequestId'] != ''){
				$orderID =  $payloadArray['origP2pRequestId'];
			}elseif(isset($payloadArray['txnId']) && $payloadArray['txnId'] != ''){
				$orderID =  $payloadArray['txnId'];
			}


			$dataArray['orderID'] = $orderID;
			$dataArray['paymentMode'] = $paymentMode;

            $status["message"] = "failed";
            $status["data"]    = $response;
            $status["request"]    = $finalArray;
            return $status;
        } catch (\Exception $e){
            echo $e->getMessage();
        }
    }

