    public static function generatePayumoneyToken($dataArray){

    	if(!isset($dataArray['chainID']) && $dataArray['chainID']==''){
    		$status['status'] = false;
    		$status['message'] = "chainID is required";
    		return $status;
    	}

    	$listOfChainsTable = Constants::getGlobalTableName("listOfChains");

    	// check the payment partner

    	$chainDetail = convertToArray(DB::table($listOfChainsTable)
    		         ->SElECT('paymentPartner','payuClientID','payuClientSecret')
    				 ->where('chainID',$dataArray['chainID'])
    				 ->get());
    	if(empty($chainDetail)){
    		$status['status'] = false;
    		$status['message'] = "Invalid chainID";
    		return $status;
    	}
    	$paymentPartner = $chainDetail[0]['paymentPartner'];
    	if ($paymentPartner != 'PAYUMONEY') {
    		$status['status'] = false;
    		$status['message'] = "invalid payment partner";
    		return $status;
    	}

    	//$payuURL = env('PAYUMONEY_URL');
    	$postData = array();
    	$postData['client_id'] = $chainDetail[0]['payuClientID'];
    	$postData['client_secret'] = $chainDetail[0]['payuClientSecret'];
    	$postData['grant_type'] = env('PAYUMONEY_GRANT_TYPE');
    	$postData['scope'] = 'password';
    	$postData['username'] = env('PAYUMONEY_USER_NAME');
    	$postData['password'] = env('PAYUMONEY_PASSWORD');
    	$sendData = json_encode($postData);
    	try{
    		$headers = [
    			'Content-Type' => 'application/json',
    		];
    		$client = new \GuzzleHttp\Client([
                    'headers' => $headers
                ]);
            $curlUrl = env('PAYUMONEY_URL')."oauth/token";
            $res = $client->request('POST', $curlUrl, ['body' => $sendData]);
            $response = json_decode($res->getBody(), true);
    	} 
    	catch(\Exception $e) {
          echo 'Message: ' .$e->getMessage();
        }

        $status['status'] = true;
        $status['data'] = $response;
        return $status;
    }


    public static function payumoneyHashGenerate($dataArray,$chainID,$recordHash=1){

	$listOfChainsTable = Constants::getGlobalTableName("listOfChains");
	$globalEcomPayuPaymentHashTable = Constants::getGlobalTableName("globalEcomPayuPaymentHash");
    	// check the payment partner
    	$chainDetail = convertToArray(DB::table($listOfChainsTable)
    		         ->SElECT('paymentPartner','payuClientID','payuClientSecret','timezone')
    				 ->where('chainID',$chainID)
    				 ->get());
    	if(empty($chainDetail)){
    		$status['status'] = false;
    		$status['message'] = "Invalid chainID";
    		return $status;
    	}
    	$paymentPartner = $chainDetail[0]['paymentPartner'];
    	if ($paymentPartner != 'PAYUMONEY') {
    		$status['status'] = false;
    		$status['message'] = "invalid payment partner";
    		return $status;
    	}
    	$env = env("APP_ENV");

    	if ($env == "test" || $env == "local") {
	    	$surl = "https://betashop.queuebuster.co/redirect/payusuccess";
	    	$furl = "https://betashop.queuebuster.co/redirect/payufailure";

    	}else{
	    	$surl = "https://shop.queuebuster.co/redirect/payusuccess";
	    	$furl = "https://shop.queuebuster.co/redirect/payufailure";

    	}
    	$salt = $chainDetail[0]['payuClientSecret'];
    	$hash = '';
    	$posted = array();
    	$posted['key'] = $chainDetail[0]['payuClientID'];
    	$posted['txnid'] = $dataArray['txnid'];
    	$posted['amount'] = $dataArray['amount'];
    	$posted['productinfo'] = $dataArray['productinfo'];
    	$posted['firstname'] = $dataArray['firstname'];
    	$posted['email'] = $dataArray['email'];
    	$posted['phone'] = $dataArray['phone'];
    	$posted['surl'] = $surl;
    	$posted['furl'] = $furl;
    	$posted['service_provider'] = "payu_paisa";


		// Hash Sequence
		// $hashSequence = "key|txnid|amount|productinfo|firstname|email|phone|surl|furl|service_provider|hash";

		$hashSequence = "key|txnid|amount|productinfo|firstname|email|udf1|udf2|udf3|udf4|udf5|udf6|udf7|udf8|udf9|udf10";
		$hashVarsSeq = explode('|', $hashSequence);
		$hashString = '';
		foreach($hashVarsSeq as $hashVar) {
	      $hashString .= isset($posted[$hashVar]) ? $posted[$hashVar] : '';
	      $hashString .= '|';
	    }
    	$hashString .= $salt;
    	$hash = strtolower(hash('sha512', $hashString));
		// $hash 	= 	strtolower(hash('sha512', $salt.'|'.'|'.$reverseKeyString));
    	$status['status'] = true;
    	$status['data'] = $hash;

    	$status['furl'] = $furl;
    	$status['surl'] = $surl;    	
    	if ($env == "test" || $env == "local") {
    		// $status["url"] = "https://sandboxsecure.payu.in";
    		$status["url"] = "https://secure.payu.in";
    	}else{
    		$status["url"] = "https://secure.payu.in";
    	}

    	$hashArray = array();
    	$timezone = $chainDetail[0]["timezone"];
        $hashArray["storeID"] = $dataArray['storeID'];
        $hashArray["chainID"] = $chainID;
        $hashArray["merchantOrderID"] = $dataArray["txnid"];
        $hashArray["amount"] = $dataArray["amount"];
        $hashArray["paymentHash"] = $hash;
        date_default_timezone_set($timezone);
        $hashArray["generatedAtLocal"] = date("Y-m-d H:i:s");
        date_default_timezone_set("UTC");
        $hashArray["generatedAtUTC"] = date("Y-m-d H:i:s");
        $hashArray["timezone"] = $timezone;
        $hashArray["status"] = "GENERATED";
    	if ($recordHash == 1) {
	        DB::transaction(function()use($hashArray,$globalEcomPayuPaymentHashTable){
	        	DB::table($globalEcomPayuPaymentHashTable)->insert($hashArray);
	        });

        }
        return $status;

    }

