			$refundArr = array();
			$refundArr["storeID"] = $storeID;
			$refundArr["chainID"] = $chainID;
			$refundArr["proformaInvoiceID"] = $proformaInvoiceID;
			$refundArr["amount"] = $refundAmount;
			$refundArr["gatewayPaymentID"] = $paymentTransactionID;
			$refundArr["refundOrderID"] = $refPINumber;
