				if (isset($refundPayArray[$i]["ID"])) {
					unset($refundPayArray[$i]["ID"]);
				}

				DB::table($globalEcomOrderPaymentsTable)->insert($refundPayArray[$i]);
				date_default_timezone_set("Asia/Kolkata");
				$PITimeLocal = date("Y-m-d H:i:s");

				date_default_timezone_set("UTC");
				$PITimeUTC = date("Y-m-d H:i:s");

				if (isset($refundPayArray[$i]["chainID"])) {
					unset($refundPayArray[$i]["chainID"]);
				}

				if (isset($refundPayArray[$i]["globalEcomCustomerID"])) {
					unset($refundPayArray[$i]["globalEcomCustomerID"]);
				}

				$refundPayArray[$i]["PITimeLocal"] = $PITimeLocal;
				$refundPayArray[$i]["PITimeUTC"] = $PITimeUTC;

				DB::table($PIPaymentsTable)->insert($refundPayArray[$i]);
			}

			DB::table($globalEcomOrderSummaryTable)->where("proformaInvoiceID",$proformaInvoiceID)->update($refSumArray);
		});

		// Send notification to customer					
		$globalCustomer = self::getGlobalCustomerDetails($chainID, $proformaInvoiceID);
		$status["globalCustomer"] = $globalCustomer;
		if (isset($globalCustomer) && !empty($globalCustomer) && $chainID != 60631) {
			$storeDetails = convertToArray(DB::table($listOfStoresTable)->where("storeID",$storeID)->select("storeName")->get());

			// Get PI Details
			$PIdetails = convertToArray(DB::select(DB::raw("SELECT A.currencyCode, A.grossBill FROM $PISummaryTable AS A  WHERE A.proformaInvoiceID = ?"),[$proformaInvoiceID]));

			$orderDetails = array();
			$orderDetails["orderID"] = $proformaInvoiceID;
			$orderDetails["storeID"] = $storeID;
			$orderDetails["storeName"] = $storeDetails[0]["storeName"];
			if(strtoupper($defaultSMS)=='SPARROW'){
				$orderDetails["orderAmount"] = "NPR ".number_format((float)$PIdetails[0]["grossBill"], 2, '.', '');
			} else{
				$orderDetails["orderAmount"] = $PIdetails[0]["currencyCode"]." ".number_format((float)$PIdetails[0]["grossBill"], 2, '.', '');
			}
			$orderDetails["defaultSMS"] = $defaultSMS;
			$orderDetails["chainID"] = $chainID;
			$orderDetails["proformaInvoiceID"] = $proformaInvoiceID;

			$notifArray = self::generateNotifArray($globalCustomer, "ORDER_UPDATE", "EXPIRED", $orderDetails);

			$queueNumber = "customer";
			if ($globalCustomer["isContactAllowed"] == 1) {
				$fcmNotificationjob = (new EcomFCMJob($notifArray))->onQueue("$queueNumber");
				$whatsappNotificationjob = (new EcomWhatsappJob($notifArray))->onQueue("$queueNumber");
				dispatch($fcmNotificationjob);
				dispatch($whatsappNotificationjob);
				$status["fcmNotificationjob"] = $fcmNotificationjob;
				$status["whatsappNotificationjob"] = $whatsappNotificationjob;
			}
			$notifArray['defaultSMS'] = $defaultSMS;
			$SMSNotificationjob = (new EcomSMSJob($notifArray))->onQueue("$queueNumber");
			dispatch($SMSNotificationjob);
			$responseStatus["SMSNotificationjob"] = $SMSNotificationjob;
			//$responseStatus["SMSNotificationjob1"] = self::sendSMS($notifArray);
			$status["notifArray"] = $notifArray;
		}

		$status["status"] = true;
		$status["message"] = "Order successfully refunded";

		return $status;


	}

